import { useMutation } from "@tanstack/react-query";

import {
  ZUploadError,
  zUploadErrorSchema,
  ZUploadResponse,
  zUploadResponseSchema,
} from "@karakeep/shared/types/uploads";

export default function useUpload({
  onSuccess,
  onError,
}: {
  onError?: (e: ZUploadError, req: File) => void;
  onSuccess?: (resp: ZUploadResponse, req: File) => Promise<void>;
}) {
  return useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append("file", file);
      const resp = await fetch("/api/assets", {
        method: "POST",
        body: formData,
      });
      if (!resp.ok) {
        throw new Error(await resp.text());
      }
      return zUploadResponseSchema.parse(await resp.json());
    },
    onSuccess: onSuccess,
    onError: (error, req) => {
      const err = zUploadErrorSchema.parse(JSON.parse(error.message));
      if (onError) {
        onError(err, req);
      }
    },
  });
}

export default function Nextcloud(
  options: OAuthUserConfig<NextcloudProfile>
): OAuthConfig<NextcloudProfile> {
  return {
    id: "nextcloud",
    name: "Nextcloud",
    type: "oauth",
    authorization: `${options.issuer}/apps/oauth2/authorize`,
    token: `${options.issuer}/apps/oauth2/api/v1/token`,
    userinfo: {
      url: `${options.issuer}/ocs/v1.php/cloud/users`,
      async request({ tokens, provider }) {
        const url = `${provider.userinfo?.url}/${tokens.user_id}`

        const res = await fetch(url, {
          headers: {
            "OCS-APIRequest": "true",
            Authorization: `Bearer ${tokens.access_token}`,
            Accept: "application/json",
          },
        }).then((res) => res.json())
        return res.ocs.data
      },
    },
    profile(profile) {
      return {
        id: profile.id,
        name: profile.displayname,
        email: profile.email,
        image: `${options.issuer}/avatar/${profile.id}/512`,
      }
    },
    style: {
      logo: "/nextcloud.svg",
      bg: "#fff",
      text: "#0082C9",
    },
    options,
  }
}

export default function Resend(config: EmailUserConfig): EmailConfig {
  return {
    id: "resend",
    type: "email",
    name: "Resend",
    from: "Auth.js <no-reply@authjs.dev>",
    maxAge: 24 * 60 * 60,
    async sendVerificationRequest(params) {
      const { identifier: to, provider, url, theme } = params
      const { host } = new URL(url)
      const res = await fetch("https://api.resend.com/emails", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${provider.apiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          from: provider.from,
          to,
          subject: `Sign in to ${host}`,
          html: html({ url, host, theme }),
          text: text({ url, host }),
        }),
      })

      if (!res.ok)
        throw new Error("Resend error: " + JSON.stringify(await res.json()))
    },
    options: config,
  }
}

export default function SendGrid(config: EmailUserConfig): EmailConfig {
  return {
    id: "sendgrid",
    type: "email",
    name: "SendGrid",
    from: "Auth.js <no-reply@authjs.dev>",
    maxAge: 24 * 60 * 60,
    async sendVerificationRequest(params) {
      const { identifier: to, provider, url, theme } = params
      const { host } = new URL(url)
      const res = await fetch("https://api.sendgrid.com/v3/mail/send", {
        method: "POST",
        headers: {
          Authorization: `Bearer ${provider.apiKey}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          personalizations: [{ to: [{ email: to }] }],
          from: { email: provider.from },
          subject: `Sign in to ${host}`,
          content: [
            { type: "text/plain", value: text({ url, host }) },
            { type: "text/html", value: html({ url, host, theme }) },
          ],
        }),
      })
      // REVIEW: Clean up error handling
      if (!res.ok) throw new Error("Sendgrid error: " + (await res.text()))
    },
    options: config,
  }
}

export function V0Button({ className }: { className?: string }) {
  const [params] = useDesignSystemSearchParams()
  const isMobile = useIsMobile()
  const isMounted = useMounted()

  const url = React.useMemo(() => {
    const searchParams = new URLSearchParams()

    if (params.preset) {
      searchParams.set("preset", params.preset)
    }

    searchParams.set("base", params.base)

    return `${process.env.NEXT_PUBLIC_APP_URL}/init/v0?${searchParams.toString()}`
  }, [params.preset, params.base])

  const title = React.useMemo(() => {
    return params.base && params.style
      ? `New ${params.base}-${params.style} project`
      : "New Project"
  }, [params.base, params.style])

  if (!isMounted) {
    return <Skeleton className="h-8 w-24 rounded-lg" />
  }

  return (
    <Button
      nativeButton={false}
      role="link"
      variant={isMobile ? "default" : "outline"}
      className={cn("h-[31px] gap-1 rounded-lg", className)}
      render={
        <a
          href={`${process.env.NEXT_PUBLIC_V0_URL}/chat/api/open?url=${url}&title=${title}`}
          target="_blank"
        />
      }
    >
      <span>Open in</span>
      <Icons.v0 className="size-5" data-icon="inline-end" />
    </Button>
  )
}

const DEFAULT_DISPLAY_NAME = "User";

function normalizeSafeDisplayName(name: string | null | undefined): string {
  const normalizedName = normalizeUserNameInput(name ?? "");
  return !containsUnsafeUserNameMarkup(name ?? "") && normalizedName
    ? normalizedName
    : DEFAULT_DISPLAY_NAME;
}

const CustomProvider = (): Adapter => {
  const adapter = DrizzleAdapter(db, {
    usersTable: users,
    accountsTable: accounts,
    sessionsTable: sessions,
    verificationTokensTable: verificationTokens,
  });

  return {
    ...adapter,
    createUser: async (user: Omit<AdapterUser, "id">) => {
      const created = await User.createRaw(db, {
        name: normalizeSafeDisplayName(user.name),
        email: user.email,
        emailVerified: user.emailVerified,
      });
      logEvent({
        "event.name": "user.signup",
        "user.id": created.id,
        "auth.provider": "oauth",
      });
      return created;
    },
  };
};

import { create } from "zustand";

interface KeyboardNavigationState {
  focusedIndex: number;
  isNavigating: boolean;
  shortcutsDialogOpen: boolean;
  setFocusedIndex: (index: number) => void;
  clearFocus: () => void;
  moveBy: (delta: number, maxIndex: number) => void;
  setShortcutsDialogOpen: (open: boolean) => void;
}

export const useKeyboardNavigationStore = create<KeyboardNavigationState>(
  (set) => ({
    focusedIndex: -1,
    isNavigating: false,
    shortcutsDialogOpen: false,

    setFocusedIndex: (index) =>
      set({ focusedIndex: index, isNavigating: true }),

    clearFocus: () => set({ focusedIndex: -1, isNavigating: false }),

    moveBy: (delta, maxIndex) =>
      set((state) => {
        if (maxIndex < 0) return state;
        if (!state.isNavigating) return { focusedIndex: 0, isNavigating: true };
        const next = Math.max(
          0,
          Math.min(state.focusedIndex + delta, maxIndex),
        );
        return { focusedIndex: next, isNavigating: true };
      }),

    setShortcutsDialogOpen: (open) => set({ shortcutsDialogOpen: open }),
  }),
);
